// Normalize RSS item + compute stable SHA-256 hash for deduping
// Outputs fields compatible with your Supabase articles insert,
// including: n8n_content_hash and content_hash (mirrored).

const crypto = require('crypto');

function normalizeWhitespace(s) {
  return String(s || '')
    .replace(/\s+/g, ' ')
    .trim();
}

function canonicalUrl(url) {
  // Remove common tracking params so hashes stay stable.
  // Keep the core URL path + essential query if any.
  try {
    const u = new URL(String(url || '').trim());
    const drop = new Set([
      'utm_source','utm_medium','utm_campaign','utm_term','utm_content',
      'at_medium','at_campaign','at_custom1','at_custom2','at_custom3',
      'fbclid','gclid','igshid','mc_cid','mc_eid'
    ]);

    // remove dropped params
    [...u.searchParams.keys()].forEach(k => {
      if (drop.has(k.toLowerCase())) u.searchParams.delete(k);
    });

    // normalize: sort params
    const params = [...u.searchParams.entries()].sort(([a],[b]) => a.localeCompare(b));
    u.search = '';
    for (const [k, v] of params) u.searchParams.append(k, v);

    // remove trailing slash
    u.pathname = u.pathname.replace(/\/+$/, '');

    return u.toString();
  } catch {
    return String(url || '').trim();
  }
}

function sha256Hex(input) {
  return crypto.createHash('sha256').update(input, 'utf8').digest('hex');
}

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

// --------- INPUT MAPPING ---------
// Adjust these if your RSS parser node uses different field names.
const rawTitle = pickFirst($json.title, $json.raw_title, $json.headline, $json.title_uk);
const rawSummary = pickFirst($json.contentSnippet, $json.summary, $json.raw_content, $json.description, $json.summary_uk);
const rawLink = pickFirst($json.link, $json.url, $json.raw_link, $json.source_url);

// If your feed metadata is attached like __feed, keep it.
const feed = ($json.__feed && typeof $json.__feed === 'object') ? $json.__feed : {};

// Your pipeline already sets source_id earlier; keep it.
const source_id = pickFirst($json.source_id, feed.source_id);

// Default sector guess (AI will override later)
const primary_sector = pickFirst($json.primary_sector, feed.primary_sector, 'infrastructure');

// Published date normalization
const published_date =
  pickFirst($json.isoDate, $json.pubDate, $json.published_date) || new Date().toISOString();

// Canonicalize content for hashing
const titleNorm = normalizeWhitespace(rawTitle);
const summaryNorm = normalizeWhitespace(rawSummary);
const urlCanon = canonicalUrl(rawLink);

// IMPORTANT: hash should be stable and not depend on translations.
// Include source_id + canonical url + normalized title.
// Add summaryNorm to reduce collision risk when same URL varies (rare but possible).
const hashMaterial = [
  'v1',
  source_id || '',
  urlCanon,
  titleNorm.toLowerCase(),
  summaryNorm.toLowerCase()
].join('|');

const n8n_content_hash = sha256Hex(hashMaterial);

// --------- OUTPUT OBJECT ---------
const out = {
  // Ukrainian fields (you currently store into title_uk / summary_uk even if source is EN)
  // Keep naming consistent with your DB columns.
  title_uk: titleNorm,
  summary_uk: summaryNorm,

  // Core metadata
  published_date: new Date(published_date).toISOString(),
  source_url: urlCanon,
  primary_sector,
  source_id: source_id || null,

  // Defaults you can override later
  article_type: pickFirst($json.article_type, 'news'),
  secondary_sectors: Array.isArray($json.secondary_sectors) ? $json.secondary_sectors : [],
  credibility_tier: Number.isFinite($json.credibility_tier) ? $json.credibility_tier : (feed.source_credibility_tier ?? 2),
  original_language: pickFirst($json.original_language, feed.language, 'uk'),
  translation_status: pickFirst($json.translation_status, 'machine'),

  // New + legacy hash fields
  n8n_content_hash,
  content_hash: n8n_content_hash, // mirror for compatibility

  // Pass through feed context for later decisions (optional)
  __feed: feed
};

return [{ json: out }];

const feed = $node["Loop Over Items"].json;

return $input.all().map((item) => ({
  json: {
    ...item.json,
    __feed: {
      source_id: feed.id,
