      source_credibility_tier: feed.credibility_tier ?? 2,
      source_verification_status: feed.verification_status ?? "pending",
      primary_sector: feed.primary_sector ?? feed.default_primary_sector ?? null,
      language: feed.language ?? "uk"
    }
  }
}));

const channel = $json?.rss?.channel;
const ch = Array.isArray(channel) ? channel[0] : channel;

let items = ch?.item ?? [];
if (!Array.isArray(items)) items = [items];

return items.map((it) => {
  const title = (it.title?.['#text'] ?? it.title ?? '').toString().trim();
  const link = (it.link?.['#text'] ?? it.link ?? '').toString().trim();
  const description = (it.description?.['#text'] ?? it.description ?? '').toString().trim();
  const guid = (it.guid?.['#text'] ?? it.guid ?? null);

  const pubDate =
    (it.pubDate?.['#text'] ?? it.pubDate ?? it.published ?? it.updated ?? null);

  return {
    json: {
      title,
      link,
      description,
      guid,
      pubDate
    }
  };
});

const feed = $json;

// hard requirement: stakeholder_id must exist
if (!feed.stakeholder_id) {
  feed.__skip_feed = true;
  feed.__skip_reason = `Missing stakeholder_id for source ${feed.id} (${feed.name_en})`;
}

return [{ json: feed }];

/**
 * Filter: UA Reconstruction Relevance
 *
 * Keeps:
 * - Anything from Ukrainian ministries / govt sources (allowlist by domain/name/stakeholder_id if present)
 * - Reconstruction / recovery / donor funding / infrastructure / housing / energy / transport / governance signals
 *
 * Drops:
 * - Generic global news unrelated to Ukraine
 * - Sports/celebrity/entertainment noise
 *
 * Outputs:
 * - Returns only items marked keep
 * - Adds __relevance_score, __relevance_reasons, __relevance_bucket
 */

function safeStr(v) {
  return (v ?? "").toString().trim();
}

function lower(v) {
  return safeStr(v).toLowerCase();
}

function tryParseUrl(u) {
  try {
    return new URL(u);
  } catch (e) {
    return null;
  }
}

function domainFromUrl(u) {
  const parsed = tryParseUrl(u);
  if (!parsed) return "";
  return parsed.hostname.replace(/^www\./, "").toLowerCase();
}

function includesAny(text, needles) {
  for (const n of needles) {
    if (text.includes(n)) return true;
  }
  return false;
}

function countMatches(text, needles) {
  let c = 0;
  for (const n of needles) {
    if (text.includes(n)) c++;
  }
  return c;
}

