  "ministry", "cabinet", "kmu", "verkhovna rada", "rada",
  "state", "government", "council of ministers",
  "містерство", "міністерство", "кабінет міністрів", "верховна рада",
  "уряд", "держав", "держслужб", "обласна", "міська рада"
];

