const UA_CORE = [
  "ukraine", "ukrainian", "kyiv", "kiev", "kharkiv", "dnipro", "odesa", "odesa",
  "lviv", "mykolaiv", "zaporizhzhia", "zaporizhia", "sumy", "chernihiv",
