  "reconstruction", "rebuild", "rebuilding", "recovery", "restoration", "renovation",
  "repair", "repairs", "damaged", "destroyed", "debris", "demining",
  "housing", "shelter", "schools", "hospitals", "clinics", "kindergarten",
