 * --- SCORING LOGIC ---
 * We use conservative thresholds:
 * - Allowlist always keeps.
 * - Otherwise require a minimum score or minimum combination of signals.
 */
const THRESHOLD_KEEP = 6; // tune: higher = stricter

function evaluateItem(item) {
  const j = item.json;

  // Use your normalized fields; adjust if your names differ
  const title = lower(j.title_uk || j.title_en || j.title || "");
  const summary = lower(j.summary_en || j.summary_uk || j.content_en || j.content_uk || j.description || "");
  const url = safeStr(j.source_url || j.article_url || j.url || "");
  const domain = domainFromUrl(url);

  // Feed/source metadata if available
  const sourceName = lower(j.source_name || j.name_en || j.feed_name || "");
  const stakeholderId = safeStr(j.stakeholder_id || j.__stakeholder_id || "");

  // --- Hard excludes ---
  const fullText = `${title}\n${summary}`;
  if (includesAny(fullText, HARD_EXCLUDE_PHRASES.map(lower))) {
    return { keep: false, score: 0, bucket: "exclude", reasons: ["Hard exclude phrase"] };
  }

  // --- Hard allow: UA government/ministry sources ---
  const govDomain = domain && GOV_DOMAIN_ALLOWLIST.has(domain);
  const govName = includesAny(sourceName, GOV_NAME_KEYWORDS) || includesAny(fullText, GOV_NAME_KEYWORDS);
  const govStakeholder = stakeholderId && MINISTRY_STAKEHOLDER_IDS.has(stakeholderId);

  if (govDomain || govStakeholder) {
    return {
      keep: true,
      score: 999,
      bucket: "gov_allowlist",
      reasons: [
        govDomain ? `Gov domain allowlist: ${domain}` : null,
        govStakeholder ? `Gov stakeholder allowlist: ${stakeholderId}` : null
      ].filter(Boolean)
    };
  }

  // --- Soft allow: gov-like name + UA context ---
  // (Keeps ministry press releases hosted on non-.gov.ua domains, but only if UA context present)
  // Example: ministry posts mirrored on partner sites.
  // We'll score it; not a guaranteed keep.

  // --- Scoring ---
  let score = 0;
  const reasons = [];

  // Noise penalty
  const noiseCount = countMatches(fullText, NOISE);
  if (noiseCount > 0) {
    score -= 3 * noiseCount;
    reasons.push(`Noise signals x${noiseCount} (-${3 * noiseCount})`);
  }

  // UA context
  const uaCount = countMatches(fullText, UA_CORE);
  if (uaCount > 0) {
    score += Math.min(8, uaCount * 2);
    reasons.push(`Ukraine context x${uaCount} (+${Math.min(8, uaCount * 2)})`);
  }

  // Reconstruction signals
  const reconCount = countMatches(fullText, RECON);
  if (reconCount > 0) {
    score += Math.min(10, reconCount * 2);
    reasons.push(`Reconstruction signals x${reconCount} (+${Math.min(10, reconCount * 2)})`);
  }

  // Donor/finance signals
  const donorCount = countMatches(fullText, DONORS_FINANCE);
  if (donorCount > 0) {
    score += Math.min(8, donorCount * 2);
    reasons.push(`Donor/finance signals x${donorCount} (+${Math.min(8, donorCount * 2)})`);
  }

  // Governance/reform signals
  const govRefCount = countMatches(fullText, GOV_REFORMS);
  if (govRefCount > 0) {
    score += Math.min(6, govRefCount * 2);
    reasons.push(`Governance/reform signals x${govRefCount} (+${Math.min(6, govRefCount * 2)})`);
  }

  // Soft gov name boost
  if (govName) {
    score += 3;
    reasons.push("Gov/ministry language (+3)");
  }

  // Domain heuristic: .gov.ua usually indicates government even if not in allowlist
  if (domain.endsWith(".gov.ua")) {
    score += 6;
    reasons.push("Domain ends with .gov.ua (+6)");
  }

  // Final rule: require either (UA + recon) OR (score threshold)
  const hasUA = uaCount > 0;
  const hasRecon = reconCount > 0;

  const keep = (hasUA && hasRecon) || score >= THRESHOLD_KEEP;

  const bucket =
    keep
      ? (hasUA && hasRecon ? "ua_recon" : "score_keep")
      : "drop";

  // Extra safety: if it’s clearly global-only and no UA signal, drop even if donors appear
  // (prevents generic “World Bank approves loan for X” without any UA mention)
  if (!hasUA && score < THRESHOLD_KEEP + 3) {
    // allow if govName is present (ministry press release might omit UA)
    if (!govName) {
      return { keep: false, score, bucket: "drop_no_ua", reasons: reasons.concat(["No UA signal"]) };
    }
  }

  return { keep, score, bucket, reasons };
}

