function stripFences(s) {
  return String(s || "")
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}

function safeParseJsonString(s) {
  const cleaned = stripFences(s);
  try {
    const parsed = JSON.parse(cleaned);
    // Must be an object
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) return parsed;
    return null;
  } catch {
    return null;
  }
}

