// Negative noise signals (drop candidates)
const NOISE = [
  "celebrity", "gossip", "movie", "film", "music", "grammy", "oscar",
  "football", "soccer", "nba", "nfl", "tennis", "match", "tournament",
  "horoscope", "recipe", "fashion", "beauty", "gaming", "esports"
