// Sometimes feeds include Ukraine but it's clearly unrelated (very rare).
// Keep this list short; you can expand later.
const HARD_EXCLUDE_PHRASES = [
  "ukraine war live blog", // if you don’t want pure war live blogs in reconstruction pipeline
];

/**
 * --- SCORING LOGIC ---
 * We use conservative thresholds:
 * - Allowlist always keeps.
 * - Otherwise require a minimum score or minimum combination of signals.
 */
const THRESHOLD_KEEP = 6; // tune: higher = stricter

function evaluateItem(item) {
  const j = item.json;

  // Use your normalized fields; adjust if your names differ
  const title = lower(j.title_uk || j.title_en || j.title || "");
  const summary = lower(j.summary_en || j.summary_uk || j.content_en || j.content_uk || j.description || "");
  const url = safeStr(j.source_url || j.article_url || j.url || "");
  const domain = domainFromUrl(url);

  // Feed/source metadata if available
  const sourceName = lower(j.source_name || j.name_en || j.feed_name || "");
  const stakeholderId = safeStr(j.stakeholder_id || j.__stakeholder_id || "");

  // --- Hard excludes ---
  const fullText = `${title}\n${summary}`;
  if (includesAny(fullText, HARD_EXCLUDE_PHRASES.map(lower))) {
    return { keep: false, score: 0, bucket: "exclude", reasons: ["Hard exclude phrase"] };
  }

  // --- Hard allow: UA government/ministry sources ---
  const govDomain = domain && GOV_DOMAIN_ALLOWLIST.has(domain);
  const govName = includesAny(sourceName, GOV_NAME_KEYWORDS) || includesAny(fullText, GOV_NAME_KEYWORDS);
  const govStakeholder = stakeholderId && MINISTRY_STAKEHOLDER_IDS.has(stakeholderId);

  if (govDomain || govStakeholder) {
    return {
      keep: true,
      score: 999,
      bucket: "gov_allowlist",
      reasons: [
        govDomain ? `Gov domain allowlist: ${domain}` : null,
        govStakeholder ? `Gov stakeholder allowlist: ${stakeholderId}` : null
      ].filter(Boolean)
    };
  }

  // --- Soft allow: gov-like name + UA context ---
  // (Keeps ministry press releases hosted on non-.gov.ua domains, but only if UA context present)
  // Example: ministry posts mirrored on partner sites.
  // We'll score it; not a guaranteed keep.

  // --- Scoring ---
  let score = 0;
  const reasons = [];

  // Noise penalty
  const noiseCount = countMatches(fullText, NOISE);
  if (noiseCount > 0) {
    score -= 3 * noiseCount;
    reasons.push(`Noise signals x${noiseCount} (-${3 * noiseCount})`);
  }

  // UA context
  const uaCount = countMatches(fullText, UA_CORE);
  if (uaCount > 0) {
    score += Math.min(8, uaCount * 2);
    reasons.push(`Ukraine context x${uaCount} (+${Math.min(8, uaCount * 2)})`);
  }

  // Reconstruction signals
  const reconCount = countMatches(fullText, RECON);
  if (reconCount > 0) {
    score += Math.min(10, reconCount * 2);
    reasons.push(`Reconstruction signals x${reconCount} (+${Math.min(10, reconCount * 2)})`);
  }

  // Donor/finance signals
  const donorCount = countMatches(fullText, DONORS_FINANCE);
  if (donorCount > 0) {
    score += Math.min(8, donorCount * 2);
    reasons.push(`Donor/finance signals x${donorCount} (+${Math.min(8, donorCount * 2)})`);
  }

  // Governance/reform signals
  const govRefCount = countMatches(fullText, GOV_REFORMS);
  if (govRefCount > 0) {
    score += Math.min(6, govRefCount * 2);
    reasons.push(`Governance/reform signals x${govRefCount} (+${Math.min(6, govRefCount * 2)})`);
  }

  // Soft gov name boost
  if (govName) {
    score += 3;
    reasons.push("Gov/ministry language (+3)");
  }

  // Domain heuristic: .gov.ua usually indicates government even if not in allowlist
  if (domain.endsWith(".gov.ua")) {
    score += 6;
    reasons.push("Domain ends with .gov.ua (+6)");
  }

  // Final rule: require either (UA + recon) OR (score threshold)
  const hasUA = uaCount > 0;
  const hasRecon = reconCount > 0;

  const keep = (hasUA && hasRecon) || score >= THRESHOLD_KEEP;

  const bucket =
    keep
      ? (hasUA && hasRecon ? "ua_recon" : "score_keep")
      : "drop";

  // Extra safety: if it’s clearly global-only and no UA signal, drop even if donors appear
  // (prevents generic “World Bank approves loan for X” without any UA mention)
  if (!hasUA && score < THRESHOLD_KEEP + 3) {
    // allow if govName is present (ministry press release might omit UA)
    if (!govName) {
      return { keep: false, score, bucket: "drop_no_ua", reasons: reasons.concat(["No UA signal"]) };
    }
  }

  return { keep, score, bucket, reasons };
}

const kept = [];
for (const item of $input.all()) {
  const res = evaluateItem(item);

  // Attach debug fields for traceability
  item.json.__decision = res.keep ? "keep" : "drop";
  item.json.__relevance_score = res.score;
  item.json.__relevance_bucket = res.bucket;
  item.json.__relevance_reasons = res.reasons;

  if (res.keep) kept.push(item);
}

return kept;

function stripFences(s) {
  return String(s || "")
    .trim()
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();
}

function safeParseJsonString(s) {
  const cleaned = stripFences(s);
  try {
    const parsed = JSON.parse(cleaned);
    // Must be an object
    if (parsed && typeof parsed === "object" && !Array.isArray(parsed)) return parsed;
    return null;
  } catch {
    return null;
  }
}

// 1) Base item is always an object
const base = ($json && typeof $json === "object" && !Array.isArray($json)) ? $json : {};

// 2) AI output string (may be in output, text, response depending on your AI node)
const aiRaw = base.output ?? base.text ?? base.response ?? "";

// 3) Parse AI JSON string safely
const ai = safeParseJsonString(aiRaw) || {};

// 4) Build final object (MUST be an object)
const out = {
  title_uk: base.title_uk ?? "",
  summary_uk: base.summary_uk ?? "",

  title_en: ai.title_en ?? "",
  title_de: ai.title_de ?? "",
  summary_en: ai.summary_en ?? "",
  summary_de: ai.summary_de ?? "",

  primary_sector: ai.primary_sector ?? base.primary_sector ?? "infrastructure",
  translation_status: ai.translation_status ?? "machine",

  article_type: base.article_type ?? "news",
  published_date: base.published_date ?? new Date().toISOString(),
  source_url: base.source_url ?? "",
  source_id: base.source_id ?? null,
  secondary_sectors: Array.isArray(base.secondary_sectors) ? base.secondary_sectors : [],
  credibility_tier: Number.isFinite(base.credibility_tier) ? base.credibility_tier : 2,
  original_language: base.original_language ?? "uk",
  content_hash: base.content_hash ?? null,

  processing_status: base.processing_status ?? "ready_for_review",
  requires_review: base.requires_review ?? false
};

// 5) Enforce allowed sectors
const allowed = new Set(["housing","basic infrastructure","urban-resilience","disaster-risk management"]);
if (!allowed.has(out.primary_sector)) {
  out.primary_sector = "infrastructure";
  out.requires_review = true;
  out.processing_status = "needs_enrichment";
  out.review_reason = "invalid_primary_sector_from_ai";
}

// 6) If AI fields missing, mark review but still return valid object
if (!out.title_en || !out.title_de || !out.summary_en || !out.summary_de) {
  out.requires_review = true;
  out.processing_status = "needs_enrichment";
  out.review_reason = out.review_reason ?? "ai_missing_required_fields";
}

// 7) CRITICAL: Always return json as an OBJECT
return [{ json: out }];

// Supabase "Get many rows" with Always Output Data ON can emit {} when no match.
// If a match exists, the returned item will contain at least content_hash or id.
// We produce a stable boolean flag.

const hasMatch =
  !!$json && typeof $json === "object" && (
    !!$json.id ||
    !!$json.content_hash ||
    !!$json.source_url
  );

return [{ json: { __is_duplicate: hasMatch } }];

return items.filter(item => {
  // Drop items that only contain the duplicate flag
  if (!item.json) return false;

  const keys = Object.keys(item.json);

  // If the item ONLY contains the duplicate flag, remove it
  if (keys.length === 1 && keys[0] === '__is_duplicate') {
    return false;
  }

  // Keep everything else
  return true;
});
